def square_pulse(t, tau, amp):
    y = np.zeros_like(t)
    y[np.abs(t) <= tau / 2] = amp
    return y

def triangular_pulse(t, tau, amp):
    y = np.zeros_like(t)
    mask = np.abs(t) <= tau / 2
    y[mask] = amp * (1 - 2 * np.abs(t[mask]) / tau)
    return y

def fourier_square(f, tau, amp):
    """Analytical FT of square pulse: amp*tau*sinc(f*tau)"""
    x = np.pi * f * tau
    with np.errstate(divide='ignore', invalid='ignore'):
        result = amp * tau * np.sinc(f * tau)   # np.sinc uses normalised sinc
    return result

def fourier_triangular(f, tau, amp):
    """Analytical FT of triangular pulse: amp*(tau/2)*sinc^2(f*tau/2)"""
    result = amp * (tau / 2) * np.sinc(f * tau / 2) ** 2
    return result

